import React from 'react';
import './About.css';

function About() {
  return (
    <div className="about-container">
      <h2>About HikeGear Hub</h2>
      <p>
        Welcome to <strong>HikeGear Hub</strong>, your trusted partner for top-quality hiking and outdoor adventure gear rentals.
        Whether you're planning a short hike or a long expedition, we offer a wide range of equipment designed to meet your needs.
      </p>
      <p>
        Our mission is simple: to make the great outdoors accessible to everyone. 
        From backpacks and tents to sleeping bags and hiking footwear, we provide everything you need to enjoy your outdoor adventure without the hassle of buying and maintaining gear.
      </p>
      <p>
        Why rent from us? At HikeGear Hub, we believe in sustainability and convenience. Our rental process is quick and easy, ensuring that you spend less time worrying about gear and more time enjoying nature.
      </p>
      <p>
        Ready to explore? Gear up with <strong>HikeGear Hub</strong> and make your next adventure unforgettable!
      </p>
    </div>
  );
}

export default About;
